// ============================================================
// SECTION FINDER
// ============================================================
export function findSection(query) {
  const q = query.toLowerCase();
  const results = [];

  const allActs = [
    { key: "BNS", data: BNS, type: "section" },
    { key: "BNSS", data: BNSS, type: "section" },
    { key: "BSA", data: BSA, type: "section" },
    { key: "Constitution", data: CONSTITUTION, type: "article" },
    { key: "CPC", data: CPC, type: "section" },
    { key: "NI_ACT", data: NI_ACT, type: "section" },
    { key: "HMA", data: HMA, type: "section" },
    { key: "DV_ACT", data: DV_ACT, type: "section" },
    { key: "CONSUMER", data: CONSUMER, type: "section" },
    { key: "RTI", data: RTI, type: "section" },
    { key: "TPA", data: TPA, type: "section" },
    { key: "CONTRACT", data: CONTRACT, type: "section" },
    { key: "POCSO", data: POCSO, type: "section" },
    { key: "LIMITATION", data: LIMITATION, type: "section" },
    { key: "SRA", data: SRA, type: "section" },
  ];

  for (const { key, data, type } of allActs) {
    const actMatch = data.keywords?.some(kw => q.includes(kw.toLowerCase()));
    const secs = type === "article" ? data.articles : data.sections;
    if (!secs) continue;

    for (const [num, sec] of Object.entries(secs)) {
      const kwMatch = sec.keywords?.some(kw => q.includes(kw.toLowerCase()));
      const directMatch =
        q.includes(`section ${num}`) ||
        q.includes(`sec ${num}`) ||
        q.includes(`s.${num}`) ||
        q.includes(`article ${num}`) ||
        q.includes(`art ${num}`) ||
        q.includes(`art. ${num}`) ||
        (actMatch && kwMatch);

      if (directMatch || kwMatch) {
        results.push({
          act: data.name,
          actShort: data.short,
          type,
          number: num,
          title: sec.title,
          text: sec.text,
          ipc: sec.ipc || sec.crpc || sec.ea || null,
          relevance: directMatch ? 3 : kwMatch ? 2 : 1,
        });
      }
    }
  }

  // Also find leading cases
  const caseResults = [];
  for (const [key, cases] of Object.entries(LEADING_CASES)) {
    const keyLower = key.toLowerCase();
    if (results.some(r => r.number === key.replace(/[^0-9]/g, '') || q.includes(keyLower.replace(/_/g, ' ')))) {
      caseResults.push(...cases);
    }
  }

  return {
    sections: results.sort((a, b) => b.relevance - a.relevance).slice(0, 5),
    cases: caseResults.slice(0, 3),
  };
}

// ============================================================
// INTENT DETECTOR
// ============================================================
export function detectIntent(query) {
  const q = query.toLowerCase();
  const isDraft = DRAFT_KEYWORDS.some(kw => q.includes(kw));
  const isCase = CASE_KEYWORDS.some(kw => q.includes(kw));
  const isSection = /section|dhara|article|art\.|sec\.|s\.\d|bns|bnss|bsa|ipc|crpc|cpc/.test(q);

  if (isDraft && !isCase) return 'DRAFT';
  if (isDraft && isCase) return 'DRAFT'; // draft takes priority
  if (isSection) return 'SECTION';
  if (isCase) return 'CASE';
  return 'GENERAL';
}
